{"file_path": "C:\Users\zheng\Desktop\crush-agent\internal\agent\tool.go", "content": "package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"
)

// Tool is the interface every tool must implement.
type Tool interface {
	Name() string
	Description() string
	// Parameters returns a JSON Schema map describing the tool's parameters.
	Parameters() map[string]any
	Execute(ctx context.Context, params map[string]any) (string, error)
}

// ToolSchema converts a Tool into the OpenAI tool definition format.
func ToolSchema(t Tool) map[string]any {
	return map[string]any{
		"type": "function",
		"function": map[string]any{
			"name":        t.Name(),
			"description": t.Description(),
			"parameters":  t.Parameters(),
		},
	}
}

// Registry holds all registered tools.
type Registry struct {
	tools map[string]Tool
}

// NewRegistry creates an empty tool registry.
func NewRegistry() *Registry {
	return &Registry{tools: make(map[string]Tool)}
}

// Register adds a tool to the registry.
func (r *Registry) Register(t Tool) error {
	if _, exists := r.tools[t.Name()]; exists {
		return fmt.Errorf("tool %q already registered", t.Name())
	}
	r.tools[t.Name()] = t
	return nil
}

// Get returns a tool by name.
func (r *Registry) Get(name string) (Tool, bool) {
	t, ok := r.tools[name]
	return t, ok
}

// List returns all registered tool names.
func (r *Registry) List() []string {
	names := make([]string, 0, len(r.tools))
	for n := range r.tools {
		names = append(names, n)
	}
	return names
}

// Schemas returns all tool definitions in OpenAI-compatible format.
func (r *Registry) Schemas() []map[string]any {
	out := make([]map[string]any, 0, len(r.tools))
	for _, t := range r.tools {
		out = append(out, ToolSchema(t))
	}
	return out
}

// Execute runs a tool by name with the given JSON arguments.
func (r *Registry) Execute(ctx context.Context, name, argsJSON string) (string, error) {
	t, ok := r.tools[name]
	if !ok {
		return "", fmt.Errorf("unknown tool: %s", name)
	}

	var params map[string]any
	if err := json.Unmarshal([]byte(argsJSON), &params); err != nil {
		return "", fmt.Errorf("tool %q: invalid args: %w", name, err)
	}

	return t.Execute(ctx, params)
}

// ToolCall represents a tool call from the LLM.
type ToolCall struct {
	ID      string
	Name    string
	Args    string // raw JSON arguments
	Result  string
	IsError bool
}

func (tc ToolCall) String() string {
	if tc.IsError {
		return fmt.Sprintf("  [tool] %s(%s) → ERROR: %s", tc.Name, tc.Args, tc.Result)
	}
	return fmt.Sprintf("  [tool] %s(%s) → %s", tc.Name, tc.Args, tc.Result)
}

// ToolCallsLog builds a trace string of all tool calls in a turn.
func ToolCallsLog(calls []ToolCall) string {
	if len(calls) == 0 {
		return ""
	}
	var b strings.Builder
	b.WriteString("tool calls:\n")
	for _, c := range calls {
		b.WriteString(c.String())
		b.WriteString("\n")
	}
	return b.String()
}
"}

{"content": "package agent

import (
	"encoding/json"
	"fmt"
	"sync"
	"time"
)

// MessageRole constants.
const (
	RoleUser      = "user"
	RoleAssistant = "assistant"
	RoleTool      = "tool"
	RoleSystem    = "system"
)

// Message represents a single message in the conversation.
type Message struct {
	Role       string            `json:"role"`
	Content    string            `json:"content,omitempty"`
	ToolCallID string            `json:"tool_call_id,omitempty"`
	ToolName   string            `json:"tool_name,omitempty"`
	ToolCalls  []ToolCallMessage `json:"tool_calls,omitempty"`
}

// ToolCallMessage is the LLM-format tool call inside an assistant message.
type ToolCallMessage struct {
	ID       string `json:"id"`
	Type     string `json:"type"`
	Function struct {
		Name      string `json:"name"`
		Arguments string `json:"arguments"`
	} `json:"function"`
}

// Session holds the state for one conversation.
type Session struct {
	ID        string
	Messages  []Message
	CreatedAt time.Time
	TurnCount int
}

// SessionManager manages multiple independent sessions.
type SessionManager struct {
	mu       sync.RWMutex
	sessions map[string]*Session
}

// NewSessionManager creates a new session manager.
func NewSessionManager() *SessionManager {
	return &SessionManager{
		sessions: make(map[string]*Session),
	}
}

// GetOrCreate returns an existing session or creates a new one.
func (sm *SessionManager) GetOrCreate(id string) *Session {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	if s, ok := sm.sessions[id]; ok {
		return s
	}
	s := &Session{
		ID:        id,
		Messages:  []Message{},
		CreatedAt: time.Now(),
	}
	sm.sessions[id] = s
	return s
}

// Get returns a session by ID, or nil if not found.
func (sm *SessionManager) Get(id string) *Session {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	return sm.sessions[id]
}

// List returns all session IDs.
func (sm *SessionManager) List() []string {
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	ids := make([]string, 0, len(sm.sessions))
	for id := range sm.sessions {
		ids = append(ids, id)
	}
	return ids
}

// Delete removes a session.
func (sm *SessionManager) Delete(id string) {
	sm.mu.Lock()
	defer sm.mu.Unlock()
	delete(sm.sessions, id)
}

// AddUserMessage adds a user message to a session.
func (s *Session) AddUserMessage(content string) {
	s.Messages = append(s.Messages, Message{Role: RoleUser, Content: content})
	s.TurnCount++
}

// AddAssistantMessage adds an assistant text message.
func (s *Session) AddAssistantMessage(content string) {
	s.Messages = append(s.Messages, Message{Role: RoleAssistant, Content: content})
}

// AddAssistantToolCallMessage adds an assistant message containing tool calls.
func (s *Session) AddAssistantToolCallMessage(tcs []ToolCallMessage) {
	s.Messages = append(s.Messages, Message{Role: RoleAssistant, ToolCalls: tcs})
}

// AddToolResult adds a tool result message.
func (s *Session) AddToolResult(toolCallID, toolName, result string, isError bool) {
	content := result
	if isError {
		content = fmt.Sprintf("Error: %s", result)
	}
	s.Messages = append(s.Messages, Message{
		Role:       RoleTool,
		ToolCallID: toolCallID,
		ToolName:   toolName,
		Content:    content,
	})
}

// ToOpenAIMessages converts session messages to OpenAI API format.
func (s *Session) ToOpenAIMessages() []map[string]any {
	out := make([]map[string]any, 0, len(s.Messages))
	for _, m := range s.Messages {
		switch m.Role {
		case RoleUser:
			out = append(out, map[string]any{
				"role":    RoleUser,
				"content": m.Content,
			})
		case RoleAssistant:
			msg := map[string]any{"role": RoleAssistant}
			if len(m.ToolCalls) > 0 {
				msg["content"] = m.Content
				tcs := make([]map[string]any, len(m.ToolCalls))
				for i, tc := range m.ToolCalls {
					tcs[i] = map[string]any{
						"id":   tc.ID,
						"type": "function",
						"function": map[string]any{
							"name":      tc.Function.Name,
							"arguments": tc.Function.Arguments,
						},
					}
				}
				msg["tool_calls"] = tcs
			} else {
				msg["content"] = m.Content
			}
			out = append(out, msg)
		case RoleTool:
			out = append(out, map[string]any{
				"role":       RoleTool,
				"tool_call_id": m.ToolCallID,
				"content":    m.Content,
			})
		}
	}
	return out
}

// TrimToLastN keeps only the last N messages (for context window management).
func (s *Session) TrimToLastN(n int) {
	if len(s.Messages) <= n {
		return
	}
	// Always keep the oldest user message for context, then the last n-1.
	kept := []Message{s.Messages[0]}
	kept = append(kept, s.Messages[len(s.Messages)-(n-1):]...)
	s.Messages = kept
}

// DumpJSON returns a pretty-printed JSON of the session for debugging.
func (s *Session) DumpJSON() string {
	b, _ := json.MarshalIndent(s, "", "  ")
	return string(b)
}
