{"content": "package agent

import (
	"fmt"
	"log"
)

// ContextManager handles context window limits and compression.
type ContextManager struct {
	MaxTurns    int // max conversation turns before forcing compression
	MaxMessages int // max messages before trimming
}

// NewContextManager creates a context manager with defaults.
func NewContextManager() *ContextManager {
	return &ContextManager{
		MaxTurns:    50,
		MaxMessages: 30,
	}
}

// CheckAndCompress checks if the session needs compression and applies it.
// Returns a summary of what was done.
func (cm *ContextManager) CheckAndCompress(sess *Session) string {
	if sess.TurnCount <= cm.MaxTurns && len(sess.Messages) <= cm.MaxMessages {
		return ""
	}

	trimmed := len(sess.Messages)
	before := sess.TurnCount

	// Strategy 1: trim to MaxMessages, keep the system prompt and first user message.
	if len(sess.Messages) > cm.MaxMessages {
		sess.TrimToLastN(cm.MaxMessages)
	}

	// Strategy 2: merge oldest user+assistant into a summary message.
	if sess.TurnCount > cm.MaxTurns {
		summary := cm.buildSummary(sess)
		// Replace oldest messages with a summary, keeping recent ones.
		keepFrom := len(sess.Messages) - cm.MaxMessages/2
		if keepFrom < 2 {
			keepFrom = 2
		}
		recent := sess.Messages[keepFrom:]
		sess.Messages = append([]Message{
			{Role: RoleSystem, Content: fmt.Sprintf("[Summary of earlier conversation: %s]", summary)},
		}, recent...)
		sess.TurnCount = cm.MaxTurns / 2
	}

	msg := fmt.Sprintf("Context compressed: %d→%d messages, turns %d→%d",
		trimmed, len(sess.Messages), before, sess.TurnCount)
	log.Println(msg)
	return msg
}

// buildSummary creates a short summary of the session's earliest messages.
func (cm *ContextManager) buildSummary(sess *Session) string {
	// Take oldest non-system messages for summarization.
	msgs := sess.Messages
	if len(msgs) < 4 {
		return "Conversation in progress"
	}

	// Summarize the first half of the conversation.
	half := len(msgs) / 2
	var topics []string
	for i, m := range msgs[:half] {
		switch m.Role {
		case RoleUser:
			content := m.Content
			if len(content) > 50 {
				content = content[:50] + "..."
			}
			topics = append(topics, fmt.Sprintf("user asked: %s", content))
		case RoleAssistant:
			if len(m.ToolCalls) > 0 {
				for _, tc := range m.ToolCalls {
					topics = append(topics, fmt.Sprintf("used tool: %s", tc.Function.Name))
				}
			} else if m.Content != "" {
				content := m.Content
				if len(content) > 80 {
					content = content[:80] + "..."
				}
				topics = append(topics, fmt.Sprintf("assistant replied: %s", content))
			}
		case RoleTool:
			topics = append(topics, fmt.Sprintf("tool %s returned result", m.ToolName))
		}
		// Only keep the first few.
		if i >= 6 {
			break
		}
	}
	return joinStrings(topics, "; ")
}

func joinStrings(items []string, sep string) string {
	if len(items) == 0 {
		return ""
	}
	result := items[0]
	for _, item := range items[1:] {
		result += sep + item
	}
	return result
}
