{"content": "package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"time"

	openai "github.com/sashabaranov/go-openai"
)

const (
	systemPrompt = `You are an AI assistant with access to tools. Follow these rules strictly:

1. When you need to use a tool to answer the user's question, respond with a tool call.
2. When you have enough information to answer, respond directly in natural language.
3. Always explain your reasoning briefly before calling a tool.
4. If a tool returns an error, tell the user and suggest alternatives.

Available tools will be provided in the conversation.`
)

// Agent is the core agent runtime that orchestrates the LLM loop.
type Agent struct {
	client      *openai.Client
	model       string
	registry    *Registry
	sessions    *SessionManager
	ctxMgr      *ContextManager
	maxTurns    int
	LLMApiURL   string // base URL for the OpenAI-compatible API
	LastTrace   string // last turn's execution trace (for web display)
}

// AgentOption configures the agent.
type AgentOption func(*Agent)

func WithModel(model string) AgentOption {
	return func(a *Agent) { a.model = model }
}

func WithMaxTurns(n int) AgentOption {
	return func(a *Agent) { a.maxTurns = n }
}

func WithLLMApiURL(url string) AgentOption {
	return func(a *Agent) { a.LLMApiURL = url }
}

// NewAgent creates a new agent.
func NewAgent(apiKey string, registry *Registry, opts ...AgentOption) *Agent {
	client := openai.NewClient(apiKey)
	a := &Agent{
		client:    client,
		model:     "gpt-4o-mini",
		registry:  registry,
		sessions:  NewSessionManager(),
		ctxMgr:    NewContextManager(),
		maxTurns:  10,
		LastTrace: "",
	}
	for _, opt := range opts {
		opt(a)
	}
	if a.LLMApiURL != "" {
		cfg := openai.DefaultConfig(apiKey)
		cfg.BaseURL = a.LLMApiURL
		a.client = openai.NewClientWithConfig(cfg)
	}
	return a
}

// RunResult contains the full result of a single agent run.
type RunResult struct {
	Content   string     `json:"content"`
	Turns     int        `json:"turns"`
	ToolCalls []ToolCall `json:"tool_calls,omitempty"`
	Trace     string     `json:"trace"`
	Error     string     `json:"error,omitempty"`
}

// Run executes one user input through the full agent loop.
func (a *Agent) Run(ctx context.Context, sessionID, userInput string) (*RunResult, error) {
	sess := a.sessions.GetOrCreate(sessionID)

	// Add user message.
	sess.AddUserMessage(userInput)

	// Build trace.
	trace := fmt.Sprintf("[%s] Session %s: %s\n", time.Now().Format(time.RFC3339), sessionID, userInput)
	var allToolCalls []ToolCall

	for turn := 0; turn < a.maxTurns; turn++ {
		// Check context limits.
		if cMsg := a.ctxMgr.CheckAndCompress(sess); cMsg != "" {
			trace += cMsg + "\n"
		}

		// Call LLM.
		llmTrace, toolCalls, response, err := a.callLLM(ctx, sess)
		trace += llmTrace
		if err != nil {
			trace += fmt.Sprintf("LLM error: %v\n", err)
			a.LastTrace = trace
			return &RunResult{
				Trace: trace,
				Error: fmt.Sprintf("LLM call failed: %v", err),
			}, nil
		}

		// If no tool calls, the LLM responded directly.
		if len(toolCalls) == 0 {
			sess.AddAssistantMessage(response)
			trace += fmt.Sprintf("  → %s\n", truncate(response, 200))
			a.LastTrace = trace
			return &RunResult{
				Content:   response,
				Turns:     turn + 1,
				ToolCalls: allToolCalls,
				Trace:     trace,
			}, nil
		}

		// LLM wants to call tools.
		var tcms []ToolCallMessage
		for _, tc := range toolCalls {
			tcms = append(tcms, tc.ToolCallMessage)
		}
		sess.AddAssistantToolCallMessage(tcms)

		// Execute each tool.
		var turnToolCalls []ToolCall
		for _, tc := range toolCalls {
			tc.Result, tc.IsError = a.executeToolCall(ctx, &trace, tc)
			sess.AddToolResult(tc.ID, tc.Name, tc.Result, tc.IsError)
			turnToolCalls = append(turnToolCalls, tc)
		}
		allToolCalls = append(allToolCalls, turnToolCalls...)
	}

	// Max turns reached.
	errMsg := fmt.Sprintf("Exceeded maximum turns (%d)", a.maxTurns)
	trace += errMsg + "\n"
	a.LastTrace = trace
	return &RunResult{
		Content:   errMsg,
		Turns:     a.maxTurns,
		ToolCalls: allToolCalls,
		Trace:     trace,
		Error:     errMsg,
	}, nil
}

// toolCallResult holds parsed tool call data from the LLM response.
type toolCallResult struct {
	ToolCallMessage
	Name string
	Args string
}

// callLLM sends the session messages to the LLM and parses the response.
// Returns trace string, parsed tool calls, assistant text response, and error.
func (a *Agent) callLLM(ctx context.Context, sess *Session) (string, []ToolCall, string, error) {
	msgs := sess.ToOpenAIMessages()

	// Build the API request.
	req := openai.ChatCompletionRequest{
		Model:       a.model,
		Messages:    toRequestMessages(msgs),
		Tools:       toRequestTools(a.registry.Schemas()),
		Temperature: 0.7,
	}

	resp, err := a.client.CreateChatCompletion(ctx, req)
	if err != nil {
		return "", nil, "", fmt.Errorf("API call failed: %w", err)
	}

	if len(resp.Choices) == 0 {
		return "", nil, "", fmt.Errorf("empty response from LLM")
	}

	choice := resp.Choices[0]
	msg := choice.Message

	trace := fmt.Sprintf("  [LLM] %s (tokens: %d+%d, finish: %s)\n",
		a.model, resp.Usage.PromptTokens, resp.Usage.CompletionTokens, choice.FinishReason)

	// Parse tool calls.
	if len(msg.ToolCalls) > 0 {
		var calls []ToolCall
		for _, tc := range msg.ToolCalls {
			call := ToolCall{
				ID:   tc.ID,
				Name: tc.Function.Name,
				Args: tc.Function.Arguments,
			}
			calls = append(calls, call)
			trace += fmt.Sprintf("  [tool call] %s(%s)\n", tc.Function.Name, tc.Function.Arguments)
		}
		return trace, calls, msg.Content, nil
	}

	// Text response.
	return trace, nil, msg.Content, nil
}

// executeToolCall runs a single tool and updates the trace.
func (a *Agent) executeToolCall(ctx context.Context, trace *string, tc ToolCall) (string, bool) {
	start := time.Now()
	result, err := a.registry.Execute(ctx, tc.Name, tc.Args)
	duration := time.Since(start)

	if err != nil {
		*trace += fmt.Sprintf("  [tool error] %s(%s): %v (%v)\n", tc.Name, tc.Args, err, duration)
		return fmt.Sprintf("Error: %v", err), true
	}

	*trace += fmt.Sprintf("  [tool ok] %s → %s (%v)\n", tc.Name, truncate(result, 150), duration)
	return result, false
}

// GetSessionManager returns the session manager.
func (a *Agent) GetSessionManager() *SessionManager {
	return a.sessions
}

// toRequestMessages converts internal message format to OpenAI request format.
func toRequestMessages(msgs []map[string]any) []openai.ChatCompletionMessage {
	out := make([]openai.ChatCompletionMessage, 0, len(msgs)+1)
	// Add system prompt.
	out = append(out, openai.ChatCompletionMessage{
		Role:    openai.ChatMessageRoleSystem,
		Content: systemPrompt,
	})
	for _, m := range msgs {
		role, _ := m["role"].(string)
		content, _ := m["content"].(string)

		msg := openai.ChatCompletionMessage{
			Role:    role,
			Content: content,
		}

		// Handle tool calls in assistant messages.
		if tcs, ok := m["tool_calls"].([]map[string]any); ok && len(tcs) > 0 {
			msg.ToolCalls = make([]openai.ToolCall, len(tcs))
			for i, tc := range tcs {
				id, _ := tc["id"].(string)
				tcType, _ := tc["type"].(string)
				fn, _ := tc["function"].(map[string]any)
				fnName, _ := fn["name"].(string)
				fnArgs, _ := fn["arguments"].(string)
				msg.ToolCalls[i] = openai.ToolCall{
					ID:   id,
					Type: tcType,
					Function: openai.FunctionCall{
						Name:      fnName,
						Arguments: fnArgs,
					},
				}
			}
		}

		// Handle tool_call_id for tool role messages.
		if tid, ok := m["tool_call_id"].(string); ok {
			msg.ToolCallID = tid
		}

		out = append(out, msg)
	}
	return out
}

// toRequestTools converts internal tool schemas to OpenAI format.
func toRequestTools(schemas []map[string]any) []openai.Tool {
	out := make([]openai.Tool, len(schemas))
	for i, s := range schemas {
		fn, _ := s["function"].(map[string]any)
		name, _ := fn["name"].(string)
		desc, _ := fn["description"].(string)
		params, _ := fn["parameters"].(map[string]any)

		// Marshal parameters back to JSON for the Tool struct.
		paramsJSON, err := json.Marshal(params)
		if err != nil {
			log.Printf("Failed to marshal parameters for tool %q: %v", name, err)
			paramsJSON = []byte("{}")
		}

		out[i] = openai.Tool{
			Type: "function",
			Function: &openai.FunctionDefinition{
				Name:        name,
				Description: desc,
				Parameters:  paramsJSON,
			},
		}
	}
	return out
}

func truncate(s string, n int) string {
	if len(s) <= n {
		return s
	}
	return s[:n] + "..."
}
