{"content": "package tools

import (
	"context"
	"fmt"
	"math/rand"
	"strings"
	"sync"
	"time"
)

// Search is a mock search tool.
type Search struct {
	mu       sync.RWMutex
	index    map[string]string // keyword → result
}

// NewSearch creates a mock search tool with preset knowledge.
func NewSearch() *Search {
	return &Search{
		index: map[string]string{
			"weather": "Today's weather: Sunny, 24°C, light breeze from the north.",
			"temperature": "The global average temperature has risen by approximately 1.2°C since the pre-industrial era.",
			"capital of france": "The capital of France is Paris.",
			"population of china": "The population of China is approximately 1.41 billion as of 2024.",
			"go language": "Go (also called Golang) is a statically typed, compiled programming language designed at Google by Robert Griesemer, Rob Pike, and Ken Thompson. It was publicly announced in 2009.",
			"crush": "Crush is a terminal-based AI coding assistant built in Go by Charm, connecting to LLMs with tools to read, write, and execute code.",
			"gpt-4": "GPT-4 is a multimodal large language model created by OpenAI, released on March 14, 2023.",
			"what is ai": "Artificial Intelligence (AI) is the simulation of human intelligence in machines programmed to think and learn.",
			"weather in tokyo": "Tokyo: Partly cloudy, 18°C, humidity 65%.",
			"weather in london": "London: Overcast, 12°C, chance of rain 40%.",
			"weather in new york": "New York: Clear sky, 22°C, humidity 50%.",
		},
	}
}

func (s *Search) Name() string { return "search" }

func (s *Search) Description() string {
	return "Search for information on a given query. Returns relevant results from the knowledge base."
}

func (s *Search) Parameters() map[string]any {
	return map[string]any{
		"type": "object",
		"properties": map[string]any{
			"query": map[string]any{
				"type":        "string",
				"description": "The search query string, e.g. \"weather in Tokyo\" or \"what is AI\"",
			},
		},
		"required": []string{"query"},
	}
}

func (s *Search) Execute(_ context.Context, params map[string]any) (string, error) {
	query, _ := params["query"].(string)
	if query == "" {
		return "", fmt.Errorf("query is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	query = strings.ToLower(strings.TrimSpace(query))

	// Try exact match first.
	if result, ok := s.index[query]; ok {
		return result, nil
	}

	// Try fuzzy match.
	for key, result := range s.index {
		if strings.Contains(query, key) || strings.Contains(key, query) {
			return result, nil
		}
		// Word-level matching.
		qWords := strings.Fields(query)
		kWords := strings.Fields(key)
		for _, qw := range qWords {
			for _, kw := range kWords {
				if qw == kw {
					return result, nil
				}
			}
		}
	}

	// For privacy, don't add results dynamically - return informative message.
	return fmt.Sprintf("No exact results found for %q. Available knowledge includes: weather, temperature, geography, programming topics, AI concepts.", query), nil
}

// AddKnowledge adds a custom fact to the search index (for testing or dynamic updates).
func (s *Search) AddKnowledge(topic, result string) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.index[strings.ToLower(topic)] = result
}

// MockResponseTime simulates response delay (for testing).
var MockResponseTime = time.Duration(0)

func init() {
	_ = rand.Intn(1) // ensure rand is seeded
}
