{"content": "package tools

import (
	"context"
	"fmt"
	"strings"
	"sync"
	"time"
)

// TodoItem represents a single todo item.
type TodoItem struct {
	ID        int       `json:"id"`
	Task      string    `json:"task"`
	Done      bool      `json:"done"`
	CreatedAt time.Time `json:"created_at"`
}

// Todo is a todo list management tool.
type Todo struct {
	mu     sync.Mutex
	items  []TodoItem
	nextID int
}

// NewTodo creates a new todo list tool.
func NewTodo() *Todo {
	return &Todo{
		items:  make([]TodoItem, 0),
		nextID: 1,
	}
}

func (t *Todo) Name() string { return "todo" }

func (t *Todo) Description() string {
	return "Manage a todo list. Supports adding tasks, marking tasks as done, listing all tasks, and deleting tasks."
}

func (t *Todo) Parameters() map[string]any {
	return map[string]any{
		"type": "object",
		"properties": map[string]any{
			"action": map[string]any{
				"type": "string",
				"enum": []string{"add", "list", "done", "delete", "clear"},
				"description": "Action to perform: 'add' to create a task, 'list' to show all, 'done' to mark complete, 'delete' to remove, 'clear' to remove all",
			},
			"task": map[string]any{
				"type":        "string",
				"description": "The task description (required for 'add' and 'done' actions)",
			},
			"id": map[string]any{
				"type":        "integer",
				"description": "The task ID (required for 'done' and 'delete' actions)",
			},
		},
		"required": []string{"action"},
	}
}

func (t *Todo) Execute(_ context.Context, params map[string]any) (string, error) {
	action, _ := params["action"].(string)
	if action == "" {
		return "", fmt.Errorf("action is required")
	}

	switch action {
	case "add":
		return t.add(params)
	case "list":
		return t.list()
	case "done":
		return t.done(params)
	case "delete":
		return t.delete(params)
	case "clear":
		return t.clear()
	default:
		return "", fmt.Errorf("unknown action: %s (supported: add, list, done, delete, clear)", action)
	}
}

func (t *Todo) add(params map[string]any) (string, error) {
	task, _ := params["task"].(string)
	if task == "" {
		return "", fmt.Errorf("task is required for 'add' action")
	}

	t.mu.Lock()
	defer t.mu.Unlock()

	item := TodoItem{
		ID:        t.nextID,
		Task:      task,
		Done:      false,
		CreatedAt: time.Now(),
	}
	t.nextID++
	t.items = append(t.items, item)

	return fmt.Sprintf("✅ Added task #%d: %s (total: %d tasks)", item.ID, task, len(t.items)), nil
}

func (t *Todo) list() (string, error) {
	t.mu.Lock()
	defer t.mu.Unlock()

	if len(t.items) == 0 {
		return "📋 No tasks in the todo list.", nil
	}

	var b strings.Builder
	b.WriteString("📋 Todo List:\n")
	for _, item := range t.items {
		status := "⬜"
		if item.Done {
			status = "✅"
		}
		b.WriteString(fmt.Sprintf("  %s #%d: %s\n", status, item.ID, item.Task))
	}
	b.WriteString(fmt.Sprintf("  ───\n  Total: %d, Completed: %d, Pending: %d",
		len(t.items), countDone(t.items), len(t.items)-countDone(t.items)))
	return b.String(), nil
}

func (t *Todo) done(params map[string]any) (string, error) {
	task, _ := params["task"].(string)

	t.mu.Lock()
	defer t.mu.Unlock()

	if task != "" {
		// Mark by task name.
		for i, item := range t.items {
			if !item.Done && strings.EqualFold(item.Task, task) {
				t.items[i].Done = true
				return fmt.Sprintf("✅ Marked task #%d as done: %s", item.ID, item.Task), nil
			}
		}
		return "", fmt.Errorf("no pending task found matching %q", task)
	}

	// Mark by ID.
	id, ok := params["id"].(float64)
	if !ok {
		return "", fmt.Errorf("either 'task' or 'id' is required for 'done' action")
	}
	for i, item := range t.items {
		if item.ID == int(id) {
			t.items[i].Done = true
			return fmt.Sprintf("✅ Marked task #%d as done: %s", item.ID, item.Task), nil
		}
	}
	return "", fmt.Errorf("task #%d not found", int(id))
}

func (t *Todo) delete(params map[string]any) (string, error) {
	id, ok := params["id"].(float64)
	if !ok {
		return "", fmt.Errorf("'id' is required for 'delete' action")
	}

	t.mu.Lock()
	defer t.mu.Unlock()

	for i, item := range t.items {
		if item.ID == int(id) {
			t.items = append(t.items[:i], t.items[i+1:]...)
			return fmt.Sprintf("🗑️  Deleted task #%d: %s", item.ID, item.Task), nil
		}
	}
	return "", fmt.Errorf("task #%d not found", int(id))
}

func (t *Todo) clear() (string, error) {
	t.mu.Lock()
	defer t.mu.Unlock()
	count := len(t.items)
	t.items = make([]TodoItem, 0)
	return fmt.Sprintf("🗑️  Cleared all %d tasks.", count), nil
}

func countDone(items []TodoItem) int {
	count := 0
	for _, item := range items {
		if item.Done {
			count++
		}
	}
	return count
}
