  </div>
</div>

<div class="trace-panel" id="trace-panel">
  <h3 style="margin-bottom:12px;color:#fff;">🔄 Execution Trace</h3>
  <div id="trace-content">No trace yet.</div>
</div>
<button class="trace-toggle-btn" onclick="toggleTrace()">📋 Toggle Trace</button>

<script>
let currentSession = 'default';
let traceVisible = false;

function toggleTrace() { traceVisible = !traceVisible; document.getElementById('trace-panel').classList.toggle('open'); }

function newSession() {
  const id = 'session-' + Date.now();
  currentSession = id;
  loadSessions();
  document.getElementById('messages').innerHTML = '';
  document.getElementById('trace-content').textContent = 'No trace yet.';
}

function loadSessions() {
  fetch('/api/sessions').then(r=>r.json()).then(data => {
    const list = document.getElementById('session-list');
    if (data.length === 0) data = [{id: 'default', turns: 0}];
    list.innerHTML = data.map(s => 
      '<div class="session-item' + (s.id === currentSession ? ' active' : '') + '" onclick="switchSession(\'' + s.id + '\')">' +
      '<div class="sid">' + s.id + '</div>' +
      '<div class="turns">' + s.turns + ' turns</div></div>'
    ).join('');
  });
}

function switchSession(id) {
  currentSession = id;
  loadSessions();
  loadMessages();
}

function loadMessages() {
  fetch('/api/sessions/' + encodeURIComponent(currentSession)).then(r=>r.json()).then(data => {
    const container = document.getElementById('messages');
    container.innerHTML = '';
    if (!data || data.length === 0) {
      container.innerHTML = '<div style="text-align:center;color:#aaa;margin-top:60px;font-size:14px;">Start a conversation ✨</div>';
      return;
    }
    data.forEach(m => {
      const div = document.createElement('div');
      div.className = 'msg ' + m.role;
      div.innerHTML = '<div class="role-label">' + m.role + '</div><div class="bubble">' + m.content + '</div>';
      container.appendChild(div);
    });
    container.scrollTop = container.scrollHeight;
  });
}

function send() {
  const input = document.getElementById('input');
  const msg = input.value.trim();
  if (!msg) return;
  input.value = '';

  // Add user message to UI
  const container = document.getElementById('messages');
  const userDiv = document.createElement('div');
  userDiv.className = 'msg user';
  userDiv.innerHTML = '<div class="role-label">user</div><div class="bubble">' + escapeHtml(msg) + '</div>';
  container.appendChild(userDiv);
  container.scrollTop = container.scrollHeight;

  // Show loading
  const loadingDiv = document.createElement('div');
  loadingDiv.className = 'msg assistant';
  loadingDiv.innerHTML = '<div class="bubble"><span class="loading"></span> Thinking...</div>';
  container.appendChild(loadingDiv);
  container.scrollTop = container.scrollHeight;

  document.getElementById('send-btn').disabled = true;

  fetch('/api/chat', {
    method: 'POST',
    headers: {'Content-Type': 'application/json'},
    body: JSON.stringify({session_id: currentSession, message: msg})
  })
  .then(r => r.json())
  .then(data => {
    // Remove loading
    container.removeChild(loadingDiv);

    // Show trace
    if (data.trace) {
      document.getElementById('trace-content').textContent = data.trace;
    }

    // Show error
    if (data.error) {
      const errDiv = document.createElement('div');
      errDiv.className = 'msg assistant';
      errDiv.innerHTML = '<div class="role-label">assistant</div><div class="bubble" style="color:#e74c3c;">❌ Error: ' + escapeHtml(data.error) + '</div>';
      container.appendChild(errDiv);
      container.scrollTop = container.scrollHeight;
      return;
    }

    // Show tool calls
    if (data.tool_calls && data.tool_calls.length > 0) {
      const toolDiv = document.createElement('div');
      toolDiv.className = 'msg tool';
      let toolHtml = '<div class="role-label">tools</div><div class="bubble">';
      data.tool_calls.forEach(tc => {
        toolHtml += '🔧 <strong>' + escapeHtml(tc.name) + '</strong>(' + escapeHtml(tc.args) + ')';
        if (tc.is_error) toolHtml += ' → ❌ ' + escapeHtml(tc.result);
        else toolHtml += ' → ✅';
        toolHtml += '<br>';
      });
      toolHtml += '</div>';
      toolDiv.innerHTML = toolHtml;
      container.appendChild(toolDiv);
    }

    // Show assistant response
    const assistantDiv = document.createElement('div');
    assistantDiv.className = 'msg assistant';
    const content = data.content || '(no response)';
    assistantDiv.innerHTML = '<div class="role-label">assistant</div><div class="bubble">' + escapeHtml(content) + '</div>';
    container.appendChild(assistantDiv);
    container.scrollTop = container.scrollHeight;

    loadSessions();
  })
  .catch(err => {
    container.removeChild(loadingDiv);
    const errDiv = document.createElement('div');
    errDiv.className = 'msg assistant';
    errDiv.innerHTML = '<div class="role-label">assistant</div><div class="bubble" style="color:#e74c3c;">❌ Network error: ' + escapeHtml(err.message) + '</div>';
    container.appendChild(errDiv);
  })
  .finally(() => {
    document.getElementById('send-btn').disabled = false;
  });
}

function escapeHtml(s) {
  if (!s) return '';
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
}

// Init
loadSessions();
loadMessages();
</script>
</body>
</html>`
