import (
	"strings"
	"testing"
)

func TestContextManager_NoCompression(t *testing.T) {
	cm := NewContextManager()
	cm.MaxTurns = 10
	cm.MaxMessages = 10

	s := &Session{ID: "test"}
	for i := 0; i < 5; i++ {
		s.AddUserMessage("user msg")
		s.AddAssistantMessage("assistant msg")
	}

	result := cm.CheckAndCompress(s)
	if result != "" {
		t.Fatalf("Expected no compression for 5 messages (max 10), got: %s", result)
	}
	if len(s.Messages) != 10 {
		t.Fatalf("Expected 10 messages, got %d", len(s.Messages))
	}
}

func TestContextManager_TrimMessages(t *testing.T) {
	cm := NewContextManager()
	cm.MaxTurns = 100
	cm.MaxMessages = 6

	s := &Session{ID: "test"}
	s.AddUserMessage("first message")
	for i := 0; i < 10; i++ {
		s.AddUserMessage("user msg")
		s.AddAssistantMessage("assistant msg")
	}

	result := cm.CheckAndCompress(s)
	if result == "" {
		t.Fatal("Expected compression to occur")
	}

	// Should have been trimmed to MaxMessages (6).
	if len(s.Messages) > cm.MaxMessages {
		t.Fatalf("Messages should be <= %d, got %d", cm.MaxMessages, len(s.Messages))
	}

	// First message should be preserved.
	if s.Messages[0].Content != "first message" {
		t.Fatalf("First message should be preserved, got %q", s.Messages[0].Content)
	}
}

func TestContextManager_SummarizeTurns(t *testing.T) {
	cm := NewContextManager()
	cm.MaxTurns = 4
	cm.MaxMessages = 100

	s := &Session{ID: "test"}
	s.AddUserMessage("first message")
	s.AddAssistantMessage("first response")
	s.AddUserMessage("second message")
	s.AddAssistantMessage("second response")
	s.AddUserMessage("third message")
	s.AddAssistantMessage("third response")

	// 3 turns so far, should not trigger (max 4).
	result := cm.CheckAndCompress(s)
	if result != "" {
		t.Fatalf("Expected no compression yet, got: %s", result)
	}

	// Add more turns to trigger summarization.
	for i := 0; i < 5; i++ {
		s.AddUserMessage("extra message")
		s.AddAssistantMessage("extra response")
	}

	result = cm.CheckAndCompress(s)
	if result == "" {
		t.Fatal("Expected compression after exceeding MaxTurns")
	}

	// Should have a summary message now.
	hasSummary := false
	for _, m := range s.Messages {
		if m.Role == "system" && strings.Contains(m.Content, "Summary") {
			hasSummary = true
			break
		}
	}
	if !hasSummary {
		t.Fatal("Expected a summary system message after compression")
	}

	// Turn count should be reduced.
	if s.TurnCount > cm.MaxTurns {
		t.Fatalf("Turn count should be <= %d after compression, got %d", cm.MaxTurns, s.TurnCount)
	}
}
