{"content": "package tools

import (
	"context"
	"strings"
	"testing"
)

func TestCalculator_Basic(t *testing.T) {
	c := &Calculator{}
	tests := []struct {
		name   string
		expr   string
		expect string
	}{
		{"addition", `{"expression":"2+2"}`, "4"},
		{"subtraction", `{"expression":"10-3"}`, "7"},
		{"multiplication", `{"expression":"4*5"}`, "20"},
		{"division", `{"expression":"20/4"}`, "5"},
		{"sqrt", `{"expression":"sqrt(16)"}`, "4"},
		{"power", `{"expression":"2**10"}`, "1024"},
		{"complex", `{"expression":"3+4*2"}`, "11"},
		{"parentheses", `{"expression":"(3+4)*2"}`, "14"},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result, err := c.Execute(context.Background(), map[string]any{
				"expression": tt.expr[1 : len(tt.expr)-1], // strip quotes for JSON
			})
			if err != nil {
				// Retry with raw expression value.
				result, err = c.Execute(context.Background(), map[string]any{
					"expression": strings.ReplaceAll(strings.ReplaceAll(tt.expr, `{"expression":"`, ""), `"}`, ""),
				})
				if err != nil {
					t.Fatalf("Execute failed: %v", err)
				}
			}
			if !strings.Contains(result, tt.expect) {
				t.Fatalf("Expected %q to contain %q", result, tt.expect)
			}
		})
	}
}

func TestCalculator_EdgeCases(t *testing.T) {
	c := &Calculator{}

	// Division by zero.
	_, err := c.Execute(context.Background(), map[string]any{
		"expression": "1/0",
	})
	if err == nil {
		t.Fatal("Expected error for division by zero")
	}

	// Empty expression.
	_, err = c.Execute(context.Background(), map[string]any{})
	if err == nil {
		t.Fatal("Expected error for missing expression")
	}
}

func TestCalculator_Scientific(t *testing.T) {
	c := &Calculator{}
	result, err := c.Execute(context.Background(), map[string]any{
		"expression": "sin(0)",
	})
	if err != nil {
		t.Fatalf("Execute failed: %v", err)
	}
	if !strings.Contains(result, "0") {
		t.Fatalf("Expected sin(0) to be 0, got %s", result)
	}
}

func TestSearch_ExactMatch(t *testing.T) {
	s := NewSearch()
	result, err := s.Execute(context.Background(), map[string]any{
		"query": "capital of France",
	})
	if err != nil {
		t.Fatalf("Execute failed: %v", err)
	}
	if !strings.Contains(strings.ToLower(result), "paris") {
		t.Fatalf("Expected result about Paris, got %q", result)
	}
}

func TestSearch_FuzzyMatch(t *testing.T) {
	s := NewSearch()
	result, err := s.Execute(context.Background(), map[string]any{
		"query": "tell me about the weather",
	})
	if err != nil {
		t.Fatalf("Execute failed: %v", err)
	}
	if !strings.Contains(strings.ToLower(result), "weather") {
		t.Fatalf("Expected result about weather, got %q", result)
	}
}

func TestSearch_NoMatch(t *testing.T) {
	s := NewSearch()
	result, err := s.Execute(context.Background(), map[string]any{
		"query": "xyznonexistent12345",
	})
	if err != nil {
		t.Fatalf("Execute failed: %v", err)
	}
	if strings.Contains(result, "No exact results") {
		return // This is fine
	}
	t.Logf("Got result: %s", result)
}

func TestTodo_Add(t *testing.T) {
	td := NewTodo()
	result, err := td.Execute(context.Background(), map[string]any{
		"action": "add",
		"task":   "Buy groceries",
	})
	if err != nil {
		t.Fatalf("Add failed: %v", err)
	}
	if !strings.Contains(result, "Buy groceries") {
		t.Fatalf("Expected result to contain 'Buy groceries', got %q", result)
	}
}

func TestTodo_List(t *testing.T) {
	td := NewTodo()
	td.Execute(context.Background(), map[string]any{"action": "add", "task": "Task 1"})
	td.Execute(context.Background(), map[string]any{"action": "add", "task": "Task 2"})

	result, err := td.Execute(context.Background(), map[string]any{
		"action": "list",
	})
	if err != nil {
		t.Fatalf("List failed: %v", err)
	}
	if !strings.Contains(result, "Task 1") || !strings.Contains(result, "Task 2") {
		t.Fatalf("Expected both tasks in list, got %q", result)
	}
}

func TestTodo_Done(t *testing.T) {
	td := NewTodo()
	td.Execute(context.Background(), map[string]any{"action": "add", "task": "Task 1"})

	result, err := td.Execute(context.Background(), map[string]any{
		"action": "done",
		"task":   "Task 1",
	})
	if err != nil {
		t.Fatalf("Done failed: %v", err)
	}
	if !strings.Contains(result, "done") {
		t.Fatalf("Expected 'done' in result, got %q", result)
	}

	// Verify in list.
	listResult, _ := td.Execute(context.Background(), map[string]any{"action": "list"})
	if !strings.Contains(listResult, "✅") {
		t.Fatalf("Expected completed task to show checkmark, got %q", listResult)
	}
}

func TestTodo_Clear(t *testing.T) {
	td := NewTodo()
	td.Execute(context.Background(), map[string]any{"action": "add", "task": "Task 1"})
	td.Execute(context.Background(), map[string]any{"action": "add", "task": "Task 2"})

	result, err := td.Execute(context.Background(), map[string]any{
		"action": "clear",
	})
	if err != nil {
		t.Fatalf("Clear failed: %v", err)
	}
	if !strings.Contains(result, "2") {
		t.Fatalf("Expected '2' in result, got %q", result)
	}

	listResult, _ := td.Execute(context.Background(), map[string]any{"action": "list"})
	if !strings.Contains(listResult, "No tasks") {
		t.Fatalf("Expected 'No tasks' after clear, got %q", listResult)
	}
}

func TestTodo_UnknownAction(t *testing.T) {
	td := NewTodo()
	_, err := td.Execute(context.Background(), map[string]any{
		"action": "invalid",
	})
	if err == nil {
		t.Fatal("Expected error for unknown action")
	}
}
