import (
	"context"
	"fmt"
	"strings"
	"sync"
)

// ReadDocs provides access to documentation for various topics.
type ReadDocs struct {
	mu  sync.RWMutex
	docs map[string]string
}

// NewReadDocs creates a read_docs tool with preset documentation.
func NewReadDocs() *ReadDocs {
	return &ReadDocs{
		docs: map[string]string{
			"go": `# Go Programming Language

Go (Golang) is a statically typed, compiled language designed at Google.

Key features:
- Goroutines for concurrency
- Garbage collection
- Fast compilation
- Built-in testing
- ` + "`go fmt`" + ` for formatting

Basic syntax:
` + "```go" + `
package main
import "fmt"
func main() {
    fmt.Println("Hello, World!")
}
` + "```" + ``,
			"python": `# Python

Python is a high-level, interpreted programming language.

Key features:
- Dynamic typing
- Extensive standard library
- Easy to read syntax
- Great for data science and ML

Basic syntax:
` + "```python" + `
print("Hello, World!")
` + "```" + ``,
			"docker": `# Docker

Docker is a platform for developing, shipping, and running containers.

Key commands:
- ` + "`docker run`" + ` - Run a container
- ` + "`docker build`" + ` - Build an image
- ` + "`docker ps`" + ` - List containers
- ` + "`docker compose`" + ` - Multi-container apps`,
			"git": `# Git

Git is a distributed version control system.

Basic commands:
- ` + "`git init`" + ` - Initialize a repository
- ` + "`git add`" + ` - Stage changes
- ` + "`git commit`" + ` - Commit changes
- ` + "`git push`" + ` - Push to remote
- ` + "`git pull`" + ` - Pull from remote`,
			"linux": `# Linux Basics

Common Linux commands:
- ` + "`ls`" + ` - List files
- ` + "`cd`" + ` - Change directory
- ` + "`grep`" + ` - Search text
- ` + "`chmod`" + ` - Change permissions
- ` + "`ps`" + ` - List processes`,
			"crush": `# Crush

Crush is a terminal-based AI coding assistant built in Go by Charm.
It connects to LLMs and gives them tools to read, write, and execute code.

Architecture: internal/agent/agent.go contains the core agent loop:
Stream → ToolCall → ToolResult → Stream`,
		},
	}
}

func (d *ReadDocs) Name() string { return "read_docs" }

func (d *ReadDocs) Description() string {
	return "Read documentation for a given topic. Available topics: go, python, docker, git, linux, crush. Returns the documentation content."
}

func (d *ReadDocs) Parameters() map[string]any {
	return map[string]any{
		"type": "object",
		"properties": map[string]any{
			"topic": map[string]any{
				"type":        "string",
				"description": "The documentation topic to look up (e.g. 'go', 'python', 'docker', 'git', 'linux', 'crush')",
			},
		},
		"required": []string{"topic"},
	}
}

func (d *ReadDocs) Execute(_ context.Context, params map[string]any) (string, error) {
	topic, _ := params["topic"].(string)
	if topic == "" {
		return "", fmt.Errorf("topic is required")
	}

	d.mu.RLock()
	defer d.mu.RUnlock()

	topic = strings.ToLower(strings.TrimSpace(topic))

	// Try exact match.
	if doc, ok := d.docs[topic]; ok {
		return doc, nil
	}

	// Try fuzzy match.
	for key, doc := range d.docs {
		if strings.Contains(topic, key) || strings.Contains(key, topic) {
			return doc, nil
		}
	}

	return fmt.Sprintf("No documentation found for %q. Available topics: go, python, docker, git, linux, crush", topic), nil
}
