// WeatherCondition represents a weather forecast.
type WeatherCondition struct {
	City      string
	Condition string
	TempC     int
	Humidity  int
	Wind      string
}

// Weather is a mock weather forecast tool.
type Weather struct {
	mu      sync.RWMutex
	cities  map[string]WeatherCondition
}

// NewWeather creates a weather tool with preset forecasts.
func NewWeather() *Weather {
	return &Weather{
		cities: map[string]WeatherCondition{
			"beijing":    {City: "Beijing", Condition: "Sunny", TempC: 28, Humidity: 45, Wind: "10 km/h NW"},
			"shanghai":   {City: "Shanghai", Condition: "Partly Cloudy", TempC: 26, Humidity: 70, Wind: "15 km/h SE"},
			"shenzhen":   {City: "Shenzhen", Condition: "Thunderstorms", TempC: 31, Humidity: 85, Wind: "20 km/h S"},
			"tokyo":      {City: "Tokyo", Condition: "Cloudy", TempC: 18, Humidity: 65, Wind: "8 km/h NE"},
			"london":     {City: "London", Condition: "Overcast", TempC: 12, Humidity: 78, Wind: "12 km/h SW"},
			"new york":   {City: "New York", Condition: "Clear", TempC: 22, Humidity: 50, Wind: "10 km/h W"},
			"paris":      {City: "Paris", Condition: "Light Rain", TempC: 15, Humidity: 72, Wind: "14 km/h S"},
			"sydney":     {City: "Sydney", Condition: "Sunny", TempC: 20, Humidity: 55, Wind: "18 km/h E"},
			"moscow":     {City: "Moscow", Condition: "Snow", TempC: -5, Humidity: 60, Wind: "25 km/h N"},
			"dubai":      {City: "Dubai", Condition: "Hot & Sunny", TempC: 38, Humidity: 30, Wind: "5 km/h NW"},
			"san francisco": {City: "San Francisco", Condition: "Foggy", TempC: 16, Humidity: 80, Wind: "22 km/h W"},
			"singapore":  {City: "Singapore", Condition: "Thunderstorms", TempC: 30, Humidity: 82, Wind: "10 km/h S"},
		},
	}
}

func (w *Weather) Name() string { return "weather" }

func (w *Weather) Description() string {
	return "Get the current weather forecast for a city. Supports major cities worldwide."
}

func (w *Weather) Parameters() map[string]any {
	return map[string]any{
		"type": "object",
		"properties": map[string]any{
			"city": map[string]any{
				"type":        "string",
				"description": "The city name to get weather for, e.g. 'Beijing', 'Tokyo', 'London', 'New York'",
			},
		},
		"required": []string{"city"},
	}
}

func (w *Weather) Execute(_ context.Context, params map[string]any) (string, error) {
	city, _ := params["city"].(string)
	if city == "" {
		return "", fmt.Errorf("city is required")
	}

	w.mu.RLock()
	defer w.mu.RUnlock()

	// Normalize city name.
	normalized := normalizeCity(city)

	if cond, ok := w.cities[normalized]; ok {
		return formatWeather(cond), nil
	}

	// Try fuzzy match.
	for _, cond := range w.cities {
		if contains(strings.ToLower(cond.City), normalized) || contains(normalized, strings.ToLower(cond.City)) {
			return formatWeather(cond), nil
		}
	}

	return fmt.Sprintf("No weather data available for %q. Available cities: Beijing, Shanghai, Tokyo, London, New York, Paris, Sydney, Moscow, Dubai, Singapore, San Francisco", city), nil
}

func formatWeather(w WeatherCondition) string {
	return fmt.Sprintf("🌤️  %s Weather\nTemperature: %d°C\nCondition: %s\nHumidity: %d%%\nWind: %s",
		w.City, w.TempC, w.Condition, w.Humidity, w.Wind)
}

func normalizeCity(city string) string {
	s := strings.ToLower(strings.TrimSpace(city))
	// Handle common variants.
	replacements := map[string]string{
		"new york city": "new york",
		"nyc":           "new york",
		"sf":            "san francisco",
		"san fran":      "san francisco",
		"beijing":       "beijing",
		"shanghai":      "shanghai",
	}
	if r, ok := replacements[s]; ok {
		return r
	}
	return s
}

func contains(s, substr string) bool {
	return len(s) >= len(substr) && (s == substr || len(substr) > 0 && s != "" && (s[:len(substr)] == substr || s[len(s)-len(substr):] == substr || strings.Contains(s, substr)))
}

var strings = stringspkg{}

type stringspkg struct{}

func (stringspkg) ToLower(s string) string {
	out := make([]byte, len(s))
	for i := 0; i < len(s); i++ {
		c := s[i]
		if c >= 'A' && c <= 'Z' {
			c += 32
		}
		out[i] = c
	}
	return string(out)
}

func (stringspkg) TrimSpace(s string) string {
	i, j := 0, len(s)
	for i < j && (s[i] == ' ' || s[i] == '\t' || s[i] == '\n' || s[i] == '\r') {
		i++
	}
	j--
	for j >= i && (s[j] == ' ' || s[j] == '\t' || s[j] == '\n' || s[j] == '\r') {
		j--
	}
	return s[i : j+1]
}

func (stringspkg) Contains(s, substr string) bool {
	return len(substr) == 0 || (len(s) >= len(substr) && strings.Index(s, substr) >= 0)
}
